    public static class SessionStore {
        private final ConcurrentHashMap<String, AuthenticatedSession> sessions = new ConcurrentHashMap<>();
        private final ConcurrentHashMap<String, String> userSessionIndex = new ConcurrentHashMap<>();

        public void store(AuthenticatedSession session) {
            sessions.put(session.getSessionId(), session);
            userSessionIndex.put(session.getUserId(), session.getSessionId());
        }

        public AuthenticatedSession get(String sessionId) {
            AuthenticatedSession session = sessions.get(sessionId);
            if (session != null && session.isExpired()) {
                invalidate(sessionId);
                return null;
            }
            return session;
        }

        public AuthenticatedSession getByUserId(String userId) {
            String sessionId = userSessionIndex.get(userId);
            if (sessionId != null) {
                return get(sessionId);
            }
            return null;
        }

        public void invalidate(String sessionId) {
            AuthenticatedSession session = sessions.remove(sessionId);
            if (session != null) {
                userSessionIndex.remove(session.getUserId());
            }
        }

        public void cleanupExpired() {
            List<String> expiredIds = new ArrayList<>();
            sessions.forEach((id, session) -> {
                if (session.isExpired()) {
                    expiredIds.add(id);
                }
            });
            expiredIds.forEach(this::invalidate);
        }

        public int getActiveSessionCount() {
            cleanupExpired();
            return sessions.size();
        }
    }

